#include <stdio.h>
#include <math.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int ans = 1000000000;
        for (int x = 0; x <= 31; x++) {
            for (int y = 0; y <= 31; y++) {
                if (x != y) {
                    int M = (1 << x) + (1 << y);
                    ans = (ans < abs(N - M)) ? ans : abs(N - M);
                }
            }
        }
        printf("%d\n", ans);
    }
    return 0;
}

