code.Java:
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int ans = 1000000000;
            for (int x = 0; x <= 31; x++) {
                for (int y = 0; y <= 31; y++) {
                    if (x != y) {
                        int M = (1 << x) + (1 << y);
                        ans = Math.min(ans, Math.abs(N - M));
                    }
                }
            }
            System.out.println(ans);
        }
    }
}

